/**
 * Factory Signature Catalog — typed loader for the publish-time
 * `factory-signatures.json` artifact under `behaviors/registry/`.
 *
 * The catalog is regenerated by `tools/almadar-pattern-sync` whenever a
 * factory or its inputs change. Each entry advertises the canonical
 * entity/trait/page surface plus source-tagged trait `capabilities`
 * (introduced in `@almadar/core@7.22.0`) — the deterministic key the
 * `@almadar/core` translator uses to project domain rules onto trait
 * stacks via exact set membership.
 *
 * Loader mirrors `getBehaviorEmbeddings()` / `getBehaviorRegistry()`:
 * resolves the JSON relative to `import.meta.url` (dist-relative at
 * publish time), parses on first call, caches in memory.
 *
 * @packageDocumentation
 */

import type { FactorySignatureCatalog } from '@almadar/core';
import { resolveStdDataDir } from './data-dir.js';

// Promise-memoized: concurrent first callers share ONE in-flight load; a
// `null` (missing/invalid sidecar) is never cached so the next call retries —
// same retry semantics the result-memoized form had, minus the
// concurrent-first-load race.
let pending: Promise<FactorySignatureCatalog | null> | null = null;

function loadCatalog(): Promise<FactorySignatureCatalog | null> {
  pending ??= loadCatalogUncached().then((c) => {
    if (c === null) pending = null;
    return c;
  });
  return pending;
}

async function loadCatalogUncached(): Promise<FactorySignatureCatalog | null> {
  try {
    const { readFileSync } = await import('fs');
    const { resolve } = await import('path');
    const dir = await resolveStdDataDir();
    const raw = readFileSync(resolve(dir, 'registry', 'factory-signatures.json'), 'utf-8');
    const parsed = JSON.parse(raw) as FactorySignatureCatalog;
    if (
      typeof parsed?.generatedFromStdVersion !== 'string' ||
      !Array.isArray(parsed?.signatures)
    ) {
      return null;
    }
    return parsed;
  } catch {
    return null;
  }
}

/**
 * Return the typed factory-signature catalog. Returns `null` when the
 * JSON sidecar is missing (older std checkout that predates the
 * Phase-1 sync step, or a dev build with skipped post-build copy).
 * Consumers should treat `null` as a hard error — the catalog is the
 * deterministic source-of-truth for capability-based projection.
 */
export async function getFactorySignatureCatalog(): Promise<FactorySignatureCatalog | null> {
  return loadCatalog();
}
